const item = $input.first().json;
const since = item['Since (ISO)'];
const until = item['Until (ISO, optional)'] || new Date().toISOString();
return [{ json: { since, until, cursor: '' } }];

const data = $input.first().json;
const body = {
  query: {
    type: 'and',
    queries: [
      { type: 'object_type', object_type: 'lead' },
      {
        type: 'field_condition',
        field: { type: 'regular_field', object_type: 'lead', field_name: 'date_created' },
        condition: { type: 'moment_range', gte: data.since, lte: data.until }
      }
    ]
  },
  sort: [{
    direction: 'desc',
    field: { object_type: 'lead', type: 'regular_field', field_name: 'date_created' }
  }],
  _fields: { lead: ['id', 'display_name', 'status_label', 'date_created'] },
  _limit: 100,
  results_limit: 10000
};
if (data.cursor) body.cursor = data.cursor;
return [{ json: { requestBody: JSON.stringify(body), since: data.since, until: data.until } }];

const response = $input.first().json;
const leads = response.data || [];
const cursor = response.cursor || null;

const prev = $('Process Page').isExecuted
  ? $('Process Page').first().json
  : { collectedLeads: [], since: $('Build Body').first().json.since, until: $('Build Body').first().json.until };

const allLeads = prev.collectedLeads.concat(leads.map(l => ({
  id: l.id, name: l.display_name, status: l.status_label, date_created: l.date_created
})));

const hasMore = cursor !== null && cursor !== undefined && leads.length > 0;

return [{ json: {
  collectedLeads: allLeads,
  totalFound: allLeads.length,
  pageLeads: leads.length,
  hasMore,
  cursor: cursor || '',
  since: prev.since,
  until: prev.until,
  stoppedBecause: hasMore ? 'continuing' : (leads.length === 0 ? 'no_results' : 'last_page')
} }];

const data = $input.first().json;
const leads = data.collectedLeads || [];
const first = leads[0];
const last = leads[leads.length - 1];

const lines = [
  'Total Leads found: ' + data.totalFound,
  'Since: ' + data.since,
  'Until: ' + data.until,
  'Stopped because: ' + data.stoppedBecause,
  '',
  'Newest: ' + (first ? first.date_created + ' - ' + first.name : 'none'),
  'Oldest: ' + (last ? last.date_created + ' - ' + last.name : 'none'),
  '',
  '--- First 20 Leads ---'
];

leads.slice(0, 20).forEach((l, i) => {
  lines.push((i+1) + '. ' + l.date_created + ' | ' + l.name + ' | ' + l.status);
});

if (leads.length > 20) {
  lines.push('... and ' + (leads.length - 20) + ' more');
}

return [{ json: { formSubmittedText: lines.join('\n') } }];
